"use client"; import { useEffect, useState } from "react"; import PageHeader from "@/components/PageHeader"; import AuthGuard from "@/components/AuthGuard"; import DashboardShell from "@/components/DashboardShell"; import { userApi, User } from "@/lib/api"; export default function ProfilePage() { const [form, setForm] = useState<Partial<User>>({}); const [msg, setMsg] = useState(""); const [error, setError] = useState(""); useEffect(() => { userApi.getProfile().then(r => setForm(r.user)).catch((e:any)=>setError(e.message)); }, []); const submit = async () => { setError(""); setMsg(""); try { const res = await userApi.updateProfile(form); setForm(res.user); setMsg("Profile updated"); } catch (e:any) { setError(e.message); } }; return <AuthGuard><PageHeader title="Update profile" text="Edit your account information and profile details." /><DashboardShell><div className="card card-pad">{error && <div className="notice notice-error">{error}</div>}{msg && <div className="notice notice-ok">{msg}</div>}<div className="form-grid"><input className="input" value={form.name || ""} onChange={(e)=>setForm({ ...form, name: e.target.value })} placeholder="Full name" /><input className="input" value={form.phone || ""} onChange={(e)=>setForm({ ...form, phone: e.target.value })} placeholder="Phone" /><input className="input" value={form.city || ""} onChange={(e)=>setForm({ ...form, city: e.target.value })} placeholder="City" /><input className="input" value={form.address || ""} onChange={(e)=>setForm({ ...form, address: e.target.value })} placeholder="Address" /></div><div style={{ marginTop: 16 }}><button className="btn btn-primary" onClick={submit}>Save changes</button></div></div></DashboardShell></AuthGuard>; }
